import { useCallback, useMemo, useState, useRef, useEffect } from "react";
import type {IRadioCheckboxListItem} from "@lmb-it/kitsconcerto-types";

// --- Types ---


// 1. Boolean Mode (Switch / Single Checkbox like "Remember Me")
type BooleanParams = {
    mode: "boolean";
    value?: boolean;
    defaultValue?: boolean;
    onChange?: (checked: boolean) => void;
};

// 2. Tristate Mode (True / False / Null)
type TristateParams = {
    mode: "tristate";
    value?: boolean | null;
    defaultValue?: boolean | null;
    onChange?: (val: boolean | null) => void;
};

// 3. Single Mode (Radio Group)
type SingleParams<T> = {
    mode: "single";
    value?: T;
    defaultValue?: T;
    onChange?: (val: T) => void;
    allowDeselect?: boolean; // Optional: allow clicking selected radio to clear it
};

// 4. Multiple Mode (Checkbox Group)
type MultiParams<T> = {
    mode: "multiple";
    value?: T[];
    defaultValue?: T[];
    onChange?: (val: T[]) => void;
};

// Union of all params
type Params<T> =
    | BooleanParams
    | TristateParams
    | SingleParams<T>
    | MultiParams<T>;

// --- Helper: Compare two values safely ---
const isEqual = (a: any, b: any) => Object.is(a, b);

export default function useSelectionController<T = string>(params: Params<T>) {
    // --- 1. State Management (Controlled vs Uncontrolled) ---

    // Determine if component is controlled (has 'value' prop)
    const isControlled = "value" in params && params.value !== undefined;

    // Internal state for uncontrolled usage
    const [internalValue, setInternalValue] = useState<any>(() => {
        if (params.defaultValue !== undefined) return params.defaultValue;
        if (params.mode === "multiple") return [];
        if (params.mode === "tristate") return null; // or false, depending on preference
        if (params.mode === "boolean") return false;
        return undefined;
    });

    // Derived current value
    const value = isControlled ? params.value : internalValue;

    // --- 2. Change Handlers ---

    // Helper to trigger changes
    const triggerChange = useCallback(
        (newValue: any) => {
            if (!isControlled) {
                setInternalValue(newValue);
            }

            // TypeScript requires narrowing to call specific onChange signatures,
            // but in runtime we just call the function if it exists.
            if ((params as any).onChange) {
                (params as any).onChange(newValue);
            }
        },
        [isControlled, params]
    );

    /**
     * The main handler exposed to the UI.
     * Can be called with:
     * - No arguments (for boolean/tristate toggle)
     * - A value `T` (for single/multi)
     * - An item object `IRadioCheckboxListItem` (convenience)
     */
    const onChange = useCallback(
        (input?: T | IRadioCheckboxListItem<T>) => {
            // Extract raw value if input is an object, otherwise use input as value
            const rawValue =
                input && typeof input === "object" && "value" in input
                    ? (input as IRadioCheckboxListItem<T>).value
                    : (input as T);

            switch (params.mode) {
                case "boolean": {
                    const next = !value;
                    triggerChange(next);
                    break;
                }

                case "tristate": {
                    // Cycle: false -> true -> null -> false
                    let next: boolean | null = false;
                    if (value === false) next = true;
                    else if (value === true) next = null;
                    else if (value === null) next = false;
                    triggerChange(next);
                    break;
                }

                case "single": {
                    // Radio logic
                    if (isEqual(value, rawValue)) {
                        // If strictly radio, do nothing. If deselect allowed, clear it.
                        if ((params as SingleParams<T>).allowDeselect) {
                            triggerChange(undefined);
                        }
                    } else {
                        triggerChange(rawValue);
                    }
                    break;
                }

                case "multiple": {
                    // Checkbox Group logic
                    const currentArray = (value as T[]) || [];
                    const exists = currentArray.some((v) => isEqual(v, rawValue));

                    let nextArray: T[];
                    if (exists) {
                        nextArray = currentArray.filter((v) => !isEqual(v, rawValue));
                    } else {
                        nextArray = [...currentArray, rawValue];
                    }
                    triggerChange(nextArray);
                    break;
                }
            }
        },
        [params.mode, value, triggerChange, params] // Added params to dependency
    );

    // --- 3. Helpers ---

    /**
     * Checks if a specific item value is currently selected.
     * Useful for rendering lists (Radio Groups / Checkbox Groups).
     */
    const isSelected = useCallback(
        (itemValue: T | IRadioCheckboxListItem<T>): boolean => {
            const target =
                itemValue && typeof itemValue === "object" && "value" in itemValue
                    ? (itemValue as IRadioCheckboxListItem<T>).value
                    : (itemValue as T);

            if (params.mode === "multiple") {
                return ((value as T[]) || []).some((v) => isEqual(v, target));
            }
            if (params.mode === "single") {
                return isEqual(value, target);
            }
            // For boolean/tristate, checking specific items usually doesn't apply,
            // but we return true if the mode is 'true'.
            return value === true;
        },
        [value, params.mode]
    );

    /**
     * Boolean representation of the current state.
     * - Boolean/Tristate: returns actual value (true/false/null).
     * - Multi: returns true if array has items.
     * - Single: returns true if a value is selected.
     */
    const checked = useMemo(() => {
        if (params.mode === "multiple") return Array.isArray(value) && value.length > 0;
        if (params.mode === "single") return value !== undefined && value !== null;
        return value; // boolean or null
    }, [value, params.mode]);

    return {
        mode: params.mode,
        /**
         * The current state.
         * Type: boolean | null | T | T[]
         */
        value,

        /**
         * Call this to toggle or select an item.
         * @param input Optional. The value or item object (required for single/multi).
         */
        onChange,

        /**
         * Helper to check if a specific value is selected.
         */
        isSelected,

        /**
         * Derived boolean state (mostly for simple checkboxes).
         */
        checked,
    };
}
